functions.example_code:
-- 统计总行数
SELECT COUNT(*) AS total FROM users;

-- 统计非空城市数
SELECT COUNT(city) AS has_city FROM users;

-- 统计去重城市数
SELECT COUNT(DISTINCT city) AS unique_cities FROM users;

-- 计算所有订单的总金额
SELECT SUM(amount) AS total_amount FROM orders;

-- 计算每个用户的总消费金额
SELECT user_id, SUM(amount) AS total_spent
FROM orders GROUP BY user_id;

-- 计算所有订单的平均金额
SELECT AVG(amount) AS avg_amount FROM orders;

-- 保留两位小数
SELECT ROUND(AVG(amount), 2) AS avg_amount FROM orders;

-- 最高订单金额
SELECT MAX(amount) AS max_amount FROM orders;

-- 每个用户最近一次下单时间
SELECT user_id, MAX(order_date) AS last_order
FROM orders GROUP BY user_id;

-- 最低订单金额
SELECT MIN(amount) AS min_amount FROM orders;

-- 每个用户首单时间
SELECT user_id, MIN(order_date) AS first_order
FROM orders GROUP BY user_id;

-- 使用 CONCAT
SELECT CONCAT(first_name, ' ', last_name) AS full_name FROM employees;

-- 使用 || 拼接（PG 推荐）
SELECT first_name || ' ' || last_name AS full_name FROM employees;

-- 标准 SQL 语法
SELECT SUBSTRING('abcdef' FROM 3 FOR 2) AS result;
-- 结果: cd

-- 函数式语法
SELECT SUBSTRING('abcdef', 3, 2) AS result;
-- 结果: cd

-- 字符数
SELECT name, CHAR_LENGTH(name) AS len FROM users;

-- LENGTH 等价
SELECT LENGTH('北京') AS l;
-- 结果: 2

-- 去除首尾空格
SELECT TRIM('  hello  ') AS r;
-- 结果: 'hello'

-- 去除指定字符
SELECT TRIM(BOTH 'x' FROM 'xxhelloxx') AS r;
-- 结果: 'hello'

-- 当前日期
SELECT CURRENT_DATE;

-- 计算注册了多少天
SELECT name, CURRENT_DATE - register_date AS days
FROM users;

-- 提取年份
SELECT EXTRACT(YEAR FROM order_date) AS year FROM orders;

-- 提取月份
SELECT EXTRACT(MONTH FROM order_date) AS month FROM orders;

-- 提取星期几
SELECT EXTRACT(DOW FROM order_date) AS dow FROM orders;

-- 日期格式化
SELECT TO_CHAR(order_date, 'YYYY-MM-DD') AS d FROM orders;

-- 中文格式
SELECT TO_CHAR(order_date, 'YYYY年MM月DD日') AS chinese_date FROM orders;

-- 数值格式化
SELECT TO_CHAR(123456.789, 'FM999,999.00') AS s;

-- 取整
SELECT ROUND(12.7) AS r;
-- 13

-- 保留两位小数
SELECT ROUND(3.14159::numeric, 2) AS r;
-- 3.14

-- 向下取整
SELECT FLOOR(12.9) AS r;
-- 12

-- 计算整数小时
SELECT FLOOR(duration_seconds / 3600) AS hours FROM tasks;

-- 计算盈亏的绝对值
SELECT product, ABS(profit) AS profit_abs FROM sales;

-- 距离的绝对值
SELECT ABS(end_x - start_x) AS dx FROM trips;

-- 标准 CAST
SELECT CAST('123' AS INTEGER) AS num;

-- :: 简写
SELECT '2024-01-15'::DATE AS dt;

-- 数值转 NUMERIC
SELECT (42)::NUMERIC(10,2) AS n;

-- 为 NULL 的电话提供默认值
SELECT name, COALESCE(phone, '暂无') AS contact FROM users;

-- 多级回退
SELECT COALESCE(phone, email, '无联系方式') AS contact FROM users;

-- 用逗号连接
SELECT department, STRING_AGG(name, ', ') AS employees
FROM staff GROUP BY department;

-- 排序后连接
SELECT department, STRING_AGG(name, ', ' ORDER BY salary DESC) AS employees
FROM staff GROUP BY department;

-- 将每个部门的员工名聚合成数组
SELECT department, ARRAY_AGG(name) AS employees
FROM staff GROUP BY department;

-- 按入职时间排序后聚合
SELECT department, ARRAY_AGG(name ORDER BY hire_date) AS employees
FROM staff GROUP BY department;

-- 中位数
SELECT PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY salary) AS median
FROM employees;

-- 90 百分位
SELECT PERCENTILE_CONT(0.9) WITHIN GROUP (ORDER BY salary) AS p90
FROM employees;

-- 取邮箱域名
SELECT email, SPLIT_PART(email, '@', 2) AS domain
FROM users;

-- 取 IP 第一段
SELECT SPLIT_PART('192.168.1.1', '.', 1) AS r;
-- 192

-- 提取数字
SELECT REGEXP_MATCHES('订单号 #12345 已发货', '#(\d+)');
-- 结果: {12345}

-- 提取日期
SELECT REGEXP_MATCHES('注册于 2024-06-15', '(\d{4}-\d{2}-\d{2})');

-- 字符串转 DATE
SELECT TO_DATE('2024-06-15', 'YYYY-MM-DD') AS d;

-- 自定义格式
SELECT TO_DATE('15/06/2024', 'DD/MM/YYYY') AS d;

-- 计算用户年龄
SELECT name, AGE(birth_date) AS age FROM users;

-- 计算两个日期间隔
SELECT AGE('2026-06-18', '2024-01-01') AS interval_str;

-- 按月汇总
SELECT DATE_TRUNC('month', order_time) AS month, COUNT(*) AS cnt
FROM orders GROUP BY 1;

-- 截断到天
SELECT DATE_TRUNC('day', order_time) FROM orders;

-- 展开数组为多行
SELECT UNNEST(ARRAY['A', 'B', 'C']) AS letter;
-- 三行: A / B / C

-- 展开标签列
SELECT id, UNNEST(tags) AS tag FROM articles;

-- -> 返回 JSONB
SELECT profile->'name' AS name FROM users;

-- ->> 返回文本
SELECT profile->>'age' AS age FROM users;

-- 嵌套
SELECT profile->'address'->>'city' FROM users;

-- 函数式
SELECT JSONB_EXTRACT_PATH(profile, 'address', 'city') FROM users;

-- 把空字符串变为 NULL
SELECT name, NULLIF(remark, '') AS remark_clean FROM users;

-- 防止除以零
SELECT a / NULLIF(b, 0) AS r FROM nums;

-- 取三科分数最高一门
SELECT name, GREATEST(math, english, science) AS best
FROM scores;

-- 取三科分数最低一门
SELECT name, LEAST(math, english, science) AS worst
FROM scores;

-- 生成 1 到 5
SELECT GENERATE_SERIES(1, 5);

-- 生成连续日期
SELECT GENERATE_SERIES('2024-01-01'::date, '2024-01-31'::date, '1 day') AS d;

-- 元素位置
SELECT ARRAY_POSITION(ARRAY['a','b','c','b'], 'b') AS pos;
-- 2

-- 从第3位开始查
SELECT ARRAY_POSITION(ARRAY['a','b','c','b'], 'b', 3) AS pos;
-- 4

-- 双数组
SELECT JSONB_OBJECT(ARRAY['name','age'], ARRAY['Alice','25']);
-- {"name":"Alice", "age":"25"}

-- 交替数组
SELECT JSONB_OBJECT(ARRAY['k1','v1','k2','v2']);

SELECT NOW();
-- 2026-06-18 14:30:11.123+08

SELECT CURRENT_TIMESTAMP;
